/**
 * @fileOverview Shërbimi për kërkimin e adresave në Kosovë duke përdorur Photon (OSM Fuzzy Search).
 * Optimizuar për kërkim "as-you-type" që gjen rezultate edhe me emra të pjesshëm (p.sh. "Prishtin" -> "Prishtinë").
 */

export interface SearchResult {
  name: string;
  lat: number;
  lng: number;
  displayName: string;
}

/**
 * Kërkon lokacione në Kosovë duke përdorur Photon API.
 * Photon është i shkëlqyer për kërkime jo-strikte (fuzzy) dhe funksionon shumë më mirë për navigim.
 */
export async function searchLocations(query: string): Promise<SearchResult[]> {
  if (!query || query.length < 2) return [];

  try {
    // Bounding box strikt për Kosovën: [minLon, minLat, maxLon, maxLat]
    // Photon përdor formatin: bbox=minLon,minLat,maxLon,maxLat
    const bbox = "20.0,41.8,21.8,43.3";
    const url = `https://photon.komoot.io/api/?q=${encodeURIComponent(query)}&bbox=${bbox}&limit=10&lang=sq`;
    
    const response = await fetch(url, {
      headers: {
        'Accept': 'application/json',
        'User-Agent': 'DriveRankKosova/3.0'
      }
    });
    
    const data = await response.json();

    if (!data || !data.features) return [];

    return data.features.map((feature: any) => {
      const p = feature.properties;
      const coords = feature.geometry.coordinates;
      
      // Ndërtojmë një emër të bukur për shfaqje
      const mainName = p.name || p.street || p.district || p.city || "Lokacion i panjohur";
      
      // Shto qytetin dhe shtetin për kontekst në display name
      const city = p.city ? `, ${p.city}` : (p.district ? `, ${p.district}` : "");
      const country = p.country ? `, ${p.country}` : "";
      const street = p.street ? ` (Rruga ${p.street})` : "";
      
      const fullDisplayName = `${mainName}${street}${city}${country}`;

      return {
        name: mainName,
        lat: coords[1],
        lng: coords[0],
        displayName: fullDisplayName
      };
    });
  } catch (error) {
    console.error("Kërkimi në Photon dështoi:", error);
    return [];
  }
}
