/**
 * @fileOverview Shërbimi i navigimit për llogaritjen e rrugëve duke përdorur OSRM API.
 * Mbështet llogaritjen e rrugës më të shpejtë dhe alternativave.
 */

export interface RouteData {
  coordinates: [number, number][]; // [lat, lng]
  distance: number; // metra
  duration: number; // sekonda
  summary: string;
}

export async function calculateRoutes(
  start: { lat: number; lng: number },
  end: { lat: number; lng: number }
): Promise<RouteData[]> {
  try {
    // Shtojmë alternatives=true për të marrë më shumë se një rrugë
    const url = `https://router.project-osrm.org/route/v1/driving/${start.lng},${start.lat};${end.lng},${end.lat}?overview=full&geometries=geojson&alternatives=true`;
    
    const response = await fetch(url);
    const data = await response.json();

    if (data.code !== 'Ok' || !data.routes || data.routes.length === 0) {
      return [];
    }

    return data.routes.map((route: any) => ({
      coordinates: route.geometry.coordinates.map((coord: [number, number]) => [coord[1], coord[0]]),
      distance: route.distance,
      duration: route.duration,
      summary: route.legs[0]?.summary || "Rrugë Alternative"
    }));
  } catch (error) {
    console.error("Dështoi llogaritja e rrugës:", error);
    return [];
  }
}
